import { Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

import { cn } from '../../../utils/cn'
import * as BaseOTPField from '../../base-ui/otp-field'

// MODEL

export const {
  CompletedFocusOTPFieldInput,
  CommandMessage,
  FocusOTPFieldInput,
  OTPFieldChangeReason,
  OTPFieldFocusChange,
  OTPFieldOptions,
  OTPFieldValidationType,
  OTPFieldValueChange,
  commandForFocusChange,
  commandForValueChange,
  hiddenInputId,
  inputFocusSelector,
  inputId,
  normalizeOTPValue,
  normalizeOTPValueWithDetails,
  otpFieldFocusChange,
  otpFieldInputChange,
  otpFieldKeyboardFocusChange,
  otpFieldKeyboardValueChange,
  otpFieldPasteChange,
  otpFieldSlots,
  otpFieldState,
  removeOTPCharacter,
  replaceOTPValue,
  stripOTPWhitespace,
} = BaseOTPField
export type {
  OTPFieldSlotAttributes,
  OTPFieldSlotState,
  OTPFieldState,
} from '../../base-ui/otp-field'

export const InputOTPStyleOptions = S.Struct({
  className: S.optional(S.String),
  containerClassName: S.optional(S.String),
  groupClassName: S.optional(S.String),
  slotClassName: S.optional(S.String),
  separatorClassName: S.optional(S.String),
})
export type InputOTPStyleOptions = typeof InputOTPStyleOptions.Type

// VIEW

export type InputOTPSlotAttributes<Message> =
  BaseOTPField.OTPFieldSlotAttributes<Message> &
    Readonly<{
      slot: ReadonlyArray<Attribute<Message>>
      caret: ReadonlyArray<Attribute<Message>>
      caretLine: ReadonlyArray<Attribute<Message>>
    }>

export type InputOTPAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  group: ReadonlyArray<Attribute<Message>>
  slots: ReadonlyArray<InputOTPSlotAttributes<Message>>
  hiddenInput: ReadonlyArray<Attribute<Message>>
  separator: ReadonlyArray<Attribute<Message>>
  separatorIcon: ReadonlyArray<Attribute<Message>>
  state: BaseOTPField.OTPFieldState
}>

export type ViewConfig<Message> = Omit<
  BaseOTPField.ViewConfig<Message>,
  'toView'
> &
  InputOTPStyleOptions &
  Readonly<{
    toView?: (attributes: InputOTPAttributes<Message>) => Html
  }>

export type GroupConfig<Message> = Readonly<{
  attributes: InputOTPAttributes<Message>
  indexes: ReadonlyArray<number>
  className?: string | undefined
}>

export type SeparatorConfig = Readonly<{
  className?: string | undefined
}>

export const inputOTPContainerBaseClassName =
  'cn-input-otp flex items-center has-disabled:opacity-50'

export const inputOTPInputBaseClassName = 'disabled:cursor-not-allowed'

export const inputOTPGroupBaseClassName =
  'flex items-center rounded-lg has-aria-invalid:border-destructive has-aria-invalid:ring-3 has-aria-invalid:ring-destructive/20 dark:has-aria-invalid:ring-destructive/40'

export const inputOTPSlotBaseClassName =
  'relative flex size-8 items-center justify-center border-y border-r border-input text-sm transition-all outline-none first:rounded-l-lg first:border-l last:rounded-r-lg aria-invalid:border-destructive data-[active=true]:z-10 data-[active=true]:border-ring data-[active=true]:ring-3 data-[active=true]:ring-ring/50 data-[active=true]:aria-invalid:border-destructive data-[active=true]:aria-invalid:ring-destructive/20 dark:bg-input/30 dark:data-[active=true]:aria-invalid:ring-destructive/40'

export const inputOTPSeparatorBaseClassName =
  "flex items-center [&_svg:not([class*='size-'])]:size-4"

const caretWrapperClassName =
  'pointer-events-none absolute inset-0 flex items-center justify-center'

const caretLineClassName =
  'h-4 w-px animate-caret-blink bg-foreground duration-1000'

const interactiveSlotInputClassName =
  'absolute inset-0 size-full cursor-text opacity-0 outline-none'

export const inputOTPContainerClassName = ({
  containerClassName,
}: Pick<InputOTPStyleOptions, 'containerClassName'> = {}): string =>
  cn(inputOTPContainerBaseClassName, containerClassName)

export const inputOTPInputClassName = ({
  className,
}: Pick<InputOTPStyleOptions, 'className'> = {}): string =>
  cn(inputOTPInputBaseClassName, className)

export const inputOTPGroupClassName = ({
  className,
}: Pick<InputOTPStyleOptions, 'className'> = {}): string =>
  cn(inputOTPGroupBaseClassName, className)

export const inputOTPSlotClassName = ({
  className,
}: Pick<InputOTPStyleOptions, 'className'> = {}): string =>
  cn(inputOTPSlotBaseClassName, className)

export const inputOTPSeparatorClassName = ({
  className,
}: Pick<InputOTPStyleOptions, 'className'> = {}): string =>
  cn(inputOTPSeparatorBaseClassName, className)

const shadcnRootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  className: string | undefined,
  containerClassName: string | undefined,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('slot', 'input-otp'),
  h.Class(cn(inputOTPContainerClassName({ containerClassName }), className)),
]

const shadcnInputAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  className: string | undefined,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('slot', 'input-otp-input'),
  h.Class(inputOTPInputClassName({ className })),
]

const shadcnGroupAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  className: string | undefined,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('slot', 'input-otp-group'),
  h.Class(inputOTPGroupClassName({ className })),
]

const shadcnSlotAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  slot: BaseOTPField.OTPFieldSlotState,
  className: string | undefined,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('slot', 'input-otp-slot'),
  h.DataAttribute('active', slot.isActive ? 'true' : 'false'),
  h.Class(inputOTPSlotClassName({ className })),
]

const shadcnSeparatorAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  className: string | undefined,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('slot', 'input-otp-separator'),
  h.Role('separator'),
  h.Class(inputOTPSeparatorClassName({ className })),
]

export const InputOTPGroup = <Message>(config: GroupConfig<Message>): Html => {
  const h = html<Message>()
  const includesAllSlots =
    config.indexes.length === config.attributes.state.length

  return h.div(
    [
      ...config.attributes.group,
      h.Class('relative'),
      h.Class(inputOTPGroupClassName({ className: config.className })),
    ],
    [
      ...config.indexes.flatMap(index => {
        const slot = config.attributes.slots[index]

        return slot === undefined
          ? []
          : [
              h.div(
                [...slot.slot],
                [
                  ...(slot.state.value === ''
                    ? []
                    : [h.span([h.Class('text-sm')], [slot.state.value])]),
                  ...(slot.state.isActive && slot.state.value === ''
                    ? [h.div([...slot.caret], [h.div([...slot.caretLine], [])])]
                    : []),
                  h.input([
                    ...slot.input,
                    h.Class(interactiveSlotInputClassName),
                  ]),
                ],
              ),
            ]
      }),
      ...(includesAllSlots
        ? [h.input([...config.attributes.hiddenInput])]
        : []),
    ],
  )
}

export const InputOTPSeparator = <Message>(
  config: SeparatorConfig = {},
): Html => {
  const h = html<Message>()

  return h.div(
    [...shadcnSeparatorAttributes(h, config.className)],
    [
      h.svg(
        [
          h.Attribute('data-icon', 'minus'),
          h.Attribute('viewBox', '0 0 24 24'),
          h.Attribute('fill', 'none'),
          h.Attribute('stroke', 'currentColor'),
          h.Attribute('stroke-width', '2'),
          h.Attribute('stroke-linecap', 'round'),
          h.Attribute('stroke-linejoin', 'round'),
          h.AriaHidden(true),
        ],
        [
          h.line(
            [
              h.Attribute('x1', '5'),
              h.Attribute('x2', '19'),
              h.Attribute('y1', '12'),
              h.Attribute('y2', '12'),
            ],
            [],
          ),
        ],
      ),
    ],
  )
}

const defaultToView = <Message>(
  attributes: InputOTPAttributes<Message>,
): Html => {
  const h = html<Message>()

  return h.div(
    [...attributes.root],
    [
      h.div(
        [...attributes.group],
        attributes.slots.map(slot => h.input([...slot.input])),
      ),
      h.input([...attributes.hiddenInput]),
    ],
  )
}

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const { toView = defaultToView, ...baseConfig } = config

  return BaseOTPField.view<Message>({
    ...baseConfig,
    toView: attributes =>
      toView({
        ...attributes,
        root: [
          ...attributes.root,
          ...shadcnRootAttributes(
            h,
            config.className,
            config.containerClassName,
          ),
        ],
        group: shadcnGroupAttributes(h, config.groupClassName),
        slots: attributes.slots.map(slot => ({
          ...slot,
          input: [...slot.input],
          slot: shadcnSlotAttributes(h, slot.state, config.slotClassName),
          caret: [h.Class(caretWrapperClassName)],
          caretLine: [h.Class(caretLineClassName)],
        })),
        hiddenInput: [
          ...attributes.hiddenInput,
          ...shadcnInputAttributes(h, config.className),
        ],
        separator: shadcnSeparatorAttributes(h, config.separatorClassName),
        separatorIcon: [h.Attribute('data-icon', 'minus'), h.AriaHidden(true)],
      }),
  })
}

import type { Html } from 'foldkit/html'
import { html } from 'foldkit/html'

import { view as Button } from '../button'
import { Field, FieldDescription, FieldLabel } from '../field'
import { InputOTPGroup, InputOTPSeparator, view as InputOTP } from './index'

const otp = (
  config: Readonly<{
    id?: string
    value?: string
    length?: number
    validationType?: 'numeric' | 'alpha' | 'alphanumeric' | 'none'
    disabled?: boolean
    invalid?: boolean
    required?: boolean
    dir?: string
    groupClassName?: string
    separatorClassName?: string
  }>,
): Html =>
  InputOTP<never>({
    id: config.id,
    length: config.length ?? 6,
    value: config.value,
    validationType: config.validationType,
    isDisabled: config.disabled,
    isInvalid: config.invalid,
    isRequired: config.required,
    dir: config.dir,
    toView: attributes =>
      InputOTPGroup<never>({
        attributes,
        indexes: Array.from(
          { length: attributes.state.length },
          (_item, index) => index,
        ),
        className: config.groupClassName,
      }),
  })

const splitOtp = (
  config: Readonly<{
    id?: string
    value?: string
    validationType?: 'numeric' | 'alpha' | 'alphanumeric' | 'none'
    disabled?: boolean
    invalid?: boolean
    required?: boolean
    large?: boolean
  }>,
): Html =>
  InputOTP<never>({
    id: config.id,
    length: 6,
    value: config.value,
    validationType: config.validationType,
    isDisabled: config.disabled,
    isInvalid: config.invalid,
    isRequired: config.required,
    groupClassName: config.large
      ? '*:data-[slot=input-otp-slot]:h-12 *:data-[slot=input-otp-slot]:w-11 *:data-[slot=input-otp-slot]:text-xl'
      : undefined,
    toView: attributes => {
      const h = html<never>()

      return h.div(
        [...attributes.root],
        [
          InputOTPGroup<never>({
            attributes,
            indexes: [0, 1, 2],
          }),
          InputOTPSeparator<never>(),
          InputOTPGroup<never>({
            attributes,
            indexes: [3, 4, 5],
          }),
          h.input([...attributes.hiddenInput]),
        ],
      )
    },
  })

export const InputOTPDemo = (): Html =>
  otp({
    id: 'input-otp-demo',
    value: '123456',
  })

export const InputOTPSeparatorExample = (): Html =>
  InputOTP<never>({
    id: 'input-otp-separator',
    length: 6,
    toView: attributes => {
      const h = html<never>()

      return h.div(
        [...attributes.root],
        [
          InputOTPGroup<never>({ attributes, indexes: [0, 1] }),
          InputOTPSeparator<never>(),
          InputOTPGroup<never>({ attributes, indexes: [2, 3] }),
          InputOTPSeparator<never>(),
          InputOTPGroup<never>({ attributes, indexes: [4, 5] }),
          h.input([...attributes.hiddenInput]),
        ],
      )
    },
  })

export const InputOTPDisabled = (): Html =>
  splitOtp({
    id: 'disabled',
    value: '123456',
    disabled: true,
  })

export const InputOTPAlphanumeric = (): Html =>
  splitOtp({
    id: 'input-otp-alphanumeric',
    validationType: 'alphanumeric',
  })

export const InputOTPFourDigits = (): Html =>
  otp({
    id: 'input-otp-four-digits',
    length: 4,
    validationType: 'numeric',
  })

export const InputOTPInvalid = (): Html =>
  splitOtp({
    id: 'input-otp-invalid',
    value: '000000',
    invalid: true,
  })

export const InputOTPPattern = (): Html =>
  Field<never>({
    className: 'w-fit',
    children: [
      FieldLabel<never>({
        htmlFor: 'digits-only',
        children: ['Digits Only'],
      }),
      otp({
        id: 'digits-only',
        validationType: 'numeric',
      }),
    ],
  })

export const InputOTPControlled = (): Html => {
  const h = html<never>()

  return h.div(
    [h.Class('space-y-2')],
    [
      otp({
        id: 'input-otp-controlled',
        value: '',
      }),
      h.div(
        [h.Class('text-center text-sm')],
        ['Enter your one-time password.'],
      ),
    ],
  )
}

export const InputOTPRtl = (): Html =>
  html<never>().div(
    [html<never>().Dir('rtl')],
    [
      Field<never>({
        className: 'mx-auto max-w-xs',
        children: [
          FieldLabel<never>({
            htmlFor: 'input-otp-rtl',
            dir: 'rtl',
            children: ['رمز التحقق'],
          }),
          otp({
            id: 'input-otp-rtl',
            value: '123456',
            dir: 'rtl',
          }),
        ],
      }),
    ],
  )

const localCard = (children: ReadonlyArray<Html>): Html => {
  const h = html<never>()

  return h.div(
    [
      h.DataAttribute('slot', 'card'),
      h.Class(
        'bg-card text-card-foreground flex flex-col gap-6 rounded-xl border py-6 shadow-sm mx-auto max-w-md',
      ),
    ],
    children,
  )
}

export const InputOTPForm = (): Html => {
  const h = html<never>()

  return localCard([
    h.div(
      [
        h.DataAttribute('slot', 'card-header'),
        h.Class(
          'grid auto-rows-min grid-rows-[auto_auto] items-start gap-1.5 px-6',
        ),
      ],
      [
        h.div(
          [
            h.DataAttribute('slot', 'card-title'),
            h.Class('leading-none font-semibold'),
          ],
          ['Verify your login'],
        ),
        h.div(
          [
            h.DataAttribute('slot', 'card-description'),
            h.Class('text-muted-foreground text-sm'),
          ],
          [
            'Enter the verification code we sent to your email address: m@example.com.',
          ],
        ),
      ],
    ),
    h.div(
      [h.DataAttribute('slot', 'card-content'), h.Class('px-6')],
      [
        Field<never>({
          children: [
            h.div(
              [h.Class('flex items-center justify-between')],
              [
                FieldLabel<never>({
                  htmlFor: 'otp-verification',
                  children: ['Verification code'],
                }),
                Button<never>({
                  variant: 'outline',
                  size: 'xs',
                  toView: attributes =>
                    h.button([...attributes.button], ['Resend Code']),
                }),
              ],
            ),
            splitOtp({
              id: 'otp-verification',
              required: true,
              large: true,
            }),
            FieldDescription<never>({
              children: ['I no longer have access to this email address.'],
            }),
          ],
        }),
      ],
    ),
  ])
}

